// Monta o nome do arquivo da planilha do dia (fuso de exemplo: UTC-3)
const meses = ['Janeiro','Fevereiro','Marco','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];

const agora = new Date();
const offsetLocal = -3 * 60 * 60 * 1000;
const dataLocal = new Date(agora.getTime() + (agora.getTimezoneOffset() * 60000) + offsetLocal);

const yyyy    = dataLocal.getFullYear().toString();
const mm      = String(dataLocal.getMonth() + 1).padStart(2, '0');
const dd      = String(dataLocal.getDate()).padStart(2, '0');
const nomeMes = meses[dataLocal.getMonth()];

const nomeArquivo = `Posicao Bancaria ${dd}.${mm}.${yyyy}.xlsx`;

return [{
  json: {
    yyyy, mm, dd, nomeMes,
    nomeArquivo,
    dataFormatada: `${dd}/${mm}/${yyyy}`
  }
}];

// Extrai os identificadores do arquivo a partir do resultado da busca
const searchResult = $input.first().json;
const datas       = $('Montar Nome do Arquivo').first().json;
const nomeArquivo = datas.nomeArquivo;

const containers = searchResult.value || [];
let item = null;

for (const c of containers) {
  for (const hc of (c.hitsContainers || [])) {
    for (const hit of (hc.hits || [])) {
      if ((hit.resource || {}).name === nomeArquivo) {
        item = {
          itemId:  hit.resource.id,
          driveId: hit.resource.parentReference?.driveId,
          nome:    hit.resource.name
        };
        break;
      }
    }
    if (item) break;
  }
  if (item) break;
}

if (!item) throw new Error(`Arquivo "${nomeArquivo}" nao encontrado.`);

return [{ json: { ...datas, ...item } }];

// ============================================================
// FORMATA O RESUMO EM HTML PARA O CANAL DE MENSAGENS
// Intervalo A2:B12 -> coluna A = rotulo, coluna B = valor
// ============================================================
const excelData = $input.first().json;
const datas     = $('Montar Nome do Arquivo').first().json;
const values    = excelData.values || [];

const vazio = v => v === null || v === undefined || v === '';

const temDados = values.some(row => !(vazio(row[0]) && vazio(row[1])));
if (!temDados) {
  return [{ json: { erro: 'Nenhum dado encontrado no intervalo A2:B12', mensagem: null } }];
}

function formatarMoeda(val) {
  if (vazio(val)) return '';
  if (typeof val !== 'number') return String(val).trim();
  const abs = Math.abs(val);
  const str = abs.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  return val < 0 ? `-R$ ${str}` : `R$ ${str}`;
}

const LINHAS_DESTAQUE = ['saldo final do dia', 'saldo total disponivel'];

let linhas = [];
linhas.push(`<b>POSICAO BANCARIA - ${datas.dataFormatada}</b>`);
linhas.push('-----------------------------------------');
linhas.push('');

for (const row of values) {
  const label = row[0];
  const valor = row[1];

  if (vazio(label) && vazio(valor)) { linhas.push(''); continue; }

  // Linha de titulo de secao (so texto, valor vazio)
  if (!vazio(label) && vazio(valor)) {
    linhas.push(`<b>${String(label).trim()}</b>`);
    continue;
  }

  const labelStr = String(label).trim();
  const valorStr = formatarMoeda(valor);
  const destaque = LINHAS_DESTAQUE.some(d => labelStr.toLowerCase().includes(d));

  linhas.push(destaque ? `<b>${labelStr}: ${valorStr}</b>` : `${labelStr}: ${valorStr}`);
}

linhas.push('');
linhas.push('-----------------------------------------');
linhas.push('<i>Envio automatico - dados ficticios de demonstracao</i>');

const mensagem = linhas.join('<br>\n');
return [{ json: { erro: null, mensagem } }];

// Lista de destinatarios (dados ficticios). Um item por destinatario.
const mensagem = $('Formatar Mensagem').first().json.mensagem;

const destinatarios = [
  { nome: 'Joao Silva',    email: 'joao@exemplo.com' },
  { nome: 'Maria Souza',   email: 'maria@exemplo.com' },
  { nome: 'Carlos Lima',   email: 'carlos@exemplo.com' },
  { nome: 'Ana Pereira',   email: 'ana@exemplo.com' }
];

return destinatarios.map(d => ({
  json: { nome: d.nome, email: d.email, mensagem }
}));

const data = $input.first().json;
console.error('[Posicao Bancaria] Sem dados:', JSON.stringify(data));
return [{ json: { status: 'ERRO_SEM_DADOS', timestamp: new Date().toISOString(), detalhe: data.erro } }];

const erro = $input.first().json;
console.error('[Posicao Bancaria] Falha de acesso:', JSON.stringify(erro));
return [{ json: { status: 'ERRO_ACESSO', timestamp: new Date().toISOString(), detalhe: erro.message || JSON.stringify(erro) } }];
